const item = $input.first().json;
let chatId, userId, text = '', callbackData = '', messageId, callbackId;

if (item.message) {
  chatId = item.message.chat.id;
  userId = item.message.from.id;
  text = (item.message.text || '').trim();
} else if (item.callback_query) {
  chatId = item.callback_query.message.chat.id;
  userId = item.callback_query.from.id;
  callbackData = item.callback_query.data || '';
  messageId = item.callback_query.message.message_id;
  callbackId = item.callback_query.id;
}

let action = 'unknown';
let payload = {};

if (text.startsWith('/start')) {
  action = 'start';
} else if (text.startsWith('/learn')) {
  const url = text.replace('/learn', '').trim();
  if (url && /^https?:\/\//i.test(url)) { action = 'learn'; payload.url = url; }
  else { action = 'start'; payload.invalidUrl = true; }
} else if (text.startsWith('/quiz')) {
  action = 'list_topics';
} else if (callbackData.startsWith('topic:')) {
  action = 'start_quiz';
  payload.materialId = callbackData.slice(6);
} else if (callbackData.startsWith('ans:')) {
  action = 'answer';
  payload.answer = callbackData.slice(4);
} else if (callbackData === 'quiz_now') {
  action = 'list_topics';
} else {
  action = 'start';
}

return [{ json: { action, chatId, userId, messageId, callbackId, ...payload } }];

const u = $('Route').first().json;
const raw = $input.first().json;
const html = typeof raw === 'string' ? raw : (raw.data || raw.body || JSON.stringify(raw));

const titleMatch = html.match(/<title[^>]*>([\s\S]*?)<\/title>/i);
const title = titleMatch ? titleMatch[1].replace(/\s+/g,' ').trim() : 'Untitled';

let text = html
  .replace(/<script[\s\S]*?<\/script>/gi, ' ')
  .replace(/<style[\s\S]*?<\/style>/gi, ' ')
  .replace(/<noscript[\s\S]*?<\/noscript>/gi, ' ')
  .replace(/<[^>]+>/g, ' ')
  .replace(/&nbsp;/g,' ')
  .replace(/&amp;/g,'&').replace(/&lt;/g,'<').replace(/&gt;/g,'>').replace(/&quot;/g,'"').replace(/&#39;/g,"'")
  .replace(/\s+/g, ' ')
  .trim();

if (!text || text.length < 50) {
  return [{ json: { chatId: u.chatId, text: '⚠️ Could not extract readable content from that URL.', reply_markup: {}, _skip: true } }];
}

text = text.slice(0, 8000);
return [{ json: { chatId: u.chatId, userId: u.userId, url: u.url, title, content: text } }];

parameters.text:
=You are *Teacher AI*. Analyse the learning material and produce a clear structured summary.

Return ONLY valid minified JSON (no markdown, no code fences) matching exactly this schema:
{
  "title": string,
  "difficulty": "beginner" | "intermediate" | "advanced",
  "mainConcepts": string[],
  "keyPoints": string[]  // between 5 and 7 items
,
  "summary": string      // 2-3 sentence overview
}

Material title: {{ $json.title }}

Material content:
{{ $json.content }}

parameters.jsCode:
const u = $('Route').first().json;
const cleaned = $('Clean HTML').first().json;
const aiOut = $input.first().json;

let resp = aiOut.text || aiOut.response || aiOut.output || aiOut.content || '';
if (typeof resp !== 'string') resp = JSON.stringify(resp);
resp = resp.replace(/```json|```/g, '').trim();
const jsonMatch = resp.match(/\{[\s\S]*\}/);
if (jsonMatch) resp = jsonMatch[0];

let parsed;
try { parsed = JSON.parse(resp); }
catch (e) {
  parsed = { title: cleaned.title, difficulty: 'unknown', mainConcepts: [], keyPoints: [resp.slice(0, 400)], summary: '' };
}

const sd = $getWorkflowStaticData('global');
sd.materials = sd.materials || {};
const uid = String(u.userId);
sd.materials[uid] = sd.materials[uid] || [];

const id = 'LM-' + Date.now().toString(36).toUpperCase();
const material = {
  id,
  url: cleaned.url,
  title: parsed.title || cleaned.title,
  content: cleaned.content,
  addedDate: new Date().toISOString(),
  difficulty: parsed.difficulty || 'unknown',
  summary: parsed.summary || '',
  keyPoints: parsed.keyPoints || [],
  mainConcepts: parsed.mainConcepts || []
};
sd.materials[uid].push(material);

const safe = s => String(s || '').replace(/[*_`\[\]]/g, m => '\\' + m);

const msg = `📚 *${safe(material.title)}*\n_Difficulty: ${safe(material.difficulty)}_\n\n${safe(material.summary)}\n\n*Main concepts:* ${material.mainConcepts.map(safe).join(', ') || '—'}\n\n*Key points:*\n` +
  material.keyPoints.map((p, i) => `${i + 1}. ${safe(p)}`).join('\n') +
  `\n\n_Saved as ${id}._`;

const reply_markup = { inline_keyboard: [[{ text: '📝 Take quiz on this material', callback_data: 'topic:' + id }]] };

return [{ json: { chatId: u.chatId, text: msg, reply_markup } }];

const u = $('Route').first().json;
const sd = $getWorkflowStaticData('global');
const uid = String(u.userId);
const allUsers = Object.keys(sd.materials || {});
const mats = (sd.materials && sd.materials[uid]) || [];

let text, reply_markup;
if (mats.length === 0) {
  text = `You have no saved materials yet.\nSend /learn <url> to add one.\n\n[debug] your uid=${uid}, known uids=[${allUsers.join(',')}]`;
  reply_markup = {};
} else {
  text = '📚 Your saved topics\nChoose one to start a 5-question quiz:';
  reply_markup = { inline_keyboard: mats.map(m => [{ text: (m.title || m.id).slice(0, 60), callback_data: 'topic:' + m.id }]) };
}
return [{ json: { chatId: u.chatId, text, reply_markup } }];

const u = $('Route').first().json;
const sd = $getWorkflowStaticData('global');
const uid = String(u.userId);
const mats = (sd.materials && sd.materials[uid]) || [];
const mat = mats.find(m => m.id === u.materialId);
if (!mat) {
  return [{ json: { chatId: u.chatId, text: '⚠️ Material not found. Send /quiz to see saved topics.', reply_markup: {}, _skipAI: true } }];
}
return [{ json: { chatId: u.chatId, userId: u.userId, materialId: mat.id, title: mat.title, content: mat.content } }];

parameters.text:
=You are *Examiner AI*. Based ONLY on the material below, write exactly 5 multiple-choice questions that test understanding (not trivia). Each must have 4 options A–D, exactly one correct, and a short explanation.

Return ONLY valid minified JSON (no markdown, no code fences) matching exactly:
{
  "questions": [
    { "id": "Q1", "question": string, "options": { "A": string, "B": string, "C": string, "D": string }, "correctAnswer": "A" | "B" | "C" | "D", "explanation": string }
  ]
}

Material title: {{ $json.title }}

Material content:
{{ $json.content }}

parameters.jsCode:
const u = $('Load Material').first().json;
const aiOut = $input.first().json;

let resp = aiOut.text || aiOut.response || aiOut.output || aiOut.content || '';
if (typeof resp !== 'string') resp = JSON.stringify(resp);
resp = resp.replace(/```json|```/g, '').trim();
const m = resp.match(/\{[\s\S]*\}/);
if (m) resp = m[0];

let parsed;
try { parsed = JSON.parse(resp); } catch (e) { parsed = { questions: [] }; }
const questions = (parsed.questions || []).slice(0, 5).map((q, i) => ({
  id: q.id || ('Q' + (i + 1)),
  question: q.question,
  options: q.options || {},
  correctAnswer: String(q.correctAnswer || '').toUpperCase().trim(),
  explanation: q.explanation || ''
}));

if (questions.length === 0) {
  return [{ json: { chatId: u.chatId, text: '⚠️ Failed to generate a quiz. Try /quiz again.', reply_markup: {} } }];
}

const sd = $getWorkflowStaticData('global');
sd.quizzes = sd.quizzes || {};
const uid = String(u.userId);
sd.quizzes[uid] = { materialId: u.materialId, questions, currentIdx: 0, answers: [], score: 0, startedAt: new Date().toISOString() };

const safe = s => String(s || '').replace(/[*_`\[\]]/g, x => '\\' + x);
const q = questions[0];
const text = `🧠 *Question 1/${questions.length}*\n\n${safe(q.question)}\n\n` +
  Object.entries(q.options).map(([k, v]) => `${k}) ${safe(v)}`).join('\n');
const reply_markup = { inline_keyboard: [Object.keys(q.options).map(k => ({ text: k, callback_data: 'ans:' + k }))] };

return [{ json: { chatId: u.chatId, text, reply_markup } }];

const u = $('Route').first().json;
const sd = $getWorkflowStaticData('global');
const uid = String(u.userId);
const quiz = sd.quizzes && sd.quizzes[uid];

if (!quiz || !quiz.questions || quiz.questions.length === 0) {
  return [{ json: { chatId: u.chatId, text: 'No active quiz. Send /quiz to start one.', reply_markup: {} } }];
}

const safe = s => String(s || '').replace(/[*_`\[\]]/g, x => '\\' + x);
const idx = quiz.currentIdx;
const q = quiz.questions[idx];
const userAns = String(u.answer || '').toUpperCase().trim();
const correct = String(q.correctAnswer || '').toUpperCase().trim();

const userText  = q.options && q.options[userAns]  ? String(q.options[userAns]).toLowerCase().trim()  : '';
const correctText = q.options && q.options[correct] ? String(q.options[correct]).toLowerCase().trim() : '';
const isCorrect = userAns === correct || (userText && correctText && userText === correctText);

quiz.answers.push({ qid: q.id, question: q.question, user: userAns, correct, isCorrect, explanation: q.explanation });
if (isCorrect) quiz.score++;
quiz.currentIdx++;

const feedback = isCorrect
  ? '✅ Correct!'
  : `❌ Wrong. Correct answer: *${correct}*\n_${safe(q.explanation)}_`;

if (quiz.currentIdx < quiz.questions.length) {
  const nq = quiz.questions[quiz.currentIdx];
  const text = `${feedback}\n\n🧠 *Question ${quiz.currentIdx + 1}/${quiz.questions.length}*\n\n${safe(nq.question)}\n\n` +
    Object.entries(nq.options).map(([k, v]) => `${k}) ${safe(v)}`).join('\n');
  const reply_markup = { inline_keyboard: [Object.keys(nq.options).map(k => ({ text: k, callback_data: 'ans:' + k }))] };
  return [{ json: { chatId: u.chatId, text, reply_markup } }];
}

const total = quiz.questions.length;
const pct = Math.round(quiz.score / total * 100);
let review = quiz.answers.map((a, i) =>
  `${i + 1}. ${a.isCorrect ? '✅' : '❌'} _${safe(a.question).slice(0, 80)}_` +
  (a.isCorrect ? '' : `\n   Your: ${a.user || '—'} · Correct: ${a.correct}\n   _${safe(a.explanation)}_`)
).join('\n');

const text = `${feedback}\n\n🏁 *Quiz finished!*\nScore: *${quiz.score}/${total}* (${pct}%)\n\n*Review:*\n${review}\n\nSend /quiz to try another topic.`;

delete sd.quizzes[uid];
return [{ json: { chatId: u.chatId, text, reply_markup: {} } }];
